import{random}from"../tools/random.js";class Base extends HTMLElement{constructor(){super(),window.addEventListener("blamready",this,{once:!0})}handleEvent(event){this[`on${event.type}`]&&this[`on${event.type}`](event)}fire(name,data,target=window,bubbles=!1){let event=new CustomEvent(name,{detail:data,bubbles:bubbles});target.dispatchEvent(event)}context(){let closest=this.closest("audio-blam");return closest?closest.audioContext:document.querySelector("audio-blam").audioContext}getTime(){if(this.time)return this.time;let timeElem=this.closest("[data-sampler-blam], sequencer-blam");return timeElem?.time||this.context().currentTime}get beat(){return 60/this.closest("audio-blam").bpm}get quarterBeat(){return.25*this.beat}getOut(){let idElem=this.out&&document.getElementById(this.out);if(idElem)return idElem;let descElem=!this.isChain&&this.querySelector("chain-blam");return descElem||this.closest("audio-blam")}toBoolean(name,value){Boolean(value)?this.setAttribute(name,""):this.removeAttribute(name)}beatsToHertz(beats){return 1/(this.beat*parseFloat(beats))}hertzToBeats(hertz){return 1/(this.beat*parseFloat(hertz))}convertValue(name,value,elem){return elem=elem||this,elem.conversions?.[name]?elem.conversions[name](value):value}newItem(discard,keep){if(keep.length<2)return keep[0];let subset=keep.filter(keeper=>keeper!==discard);return subset.length?random.oneOf(subset):discard}cycle(prevItem,steps){let prevIndex=prevItem?steps.indexOf(prevItem):-1;return steps[steps[prevIndex+1]?prevIndex+1:0]}between(num,low,high){return num>=low&&num<=high}watchProps(elems,func,filter=void 0,old=!1){const observer=new MutationObserver((list,observer)=>{func(list,observer)}),settings={attributes:!0,attributeFilter:filter,attributeOldValue:old};for(const elem of elems)observer.observe(elem,settings);return observer}}export{Base};